// ─── Sources: resilient to what  contains after Redis SET ────────────────
const state     = .state     || {};
const stateData = state.data      || {};
const isNewUser          = .isNewUser  === true;
const isValidationError  = !isNewUser && (.isValid === false);

// ─── User response (for existing sessions) ────────────────────────────────────
let userResponse = null;
if (!isNewUser) {
  const parseData = .first().json;
  userResponse = parseData.callbackData || parseData.userText || null;
}

// ─── Keyboard map: keyed by state.step ─────────────────────────────────────
// Centralized here so it applies identically on first ask AND on validation error
// (state.step does NOT change when isValid=false, so the right keyboard always returns)
const IK = (rows) => ({ type: 'inlineKeyboard', inlineKeyboard: { rows } });
const btn = (text, cb) => ({ text, additionalFields: { callbackData: cb } });

const KEYBOARDS = {
  ask_gender: IK([
    { row: { buttons: [btn('Hombre','male'), btn('Mujer','female')] } }
  ]),
  ask_goal: IK([
    { row: { buttons: [btn('Perder grasa','lose_fat'), btn('Ganar musculo','gain_muscle')] } },
    { row: { buttons: [btn('Mantener peso','maintain'), btn('Recomposicion corporal','recomposition')] } }
  ]),
  ask_dietary_restrictions_known: IK([
    { row: { buttons: [btn('Si, tengo','yes'), btn('No, ninguna','no')] } }
  ]),
  ask_budget: IK([
    { row: { buttons: [btn('Economico','low'), btn('Moderado','medium'), btn('Sin limite','high')] } }
  ]),
  ask_meals: IK([
    { row: { buttons: [btn('3','3'), btn('4','4'), btn('5','5')] } }
  ]),
  ask_fitness_level: IK([
    { row: { buttons: [btn('Principiante (< 6 meses)','beginner')] } },
    { row: { buttons: [btn('Intermedio (6 meses - 2 anos)','intermediate')] } },
    { row: { buttons: [btn('Avanzado (2+ anos)','advanced')] } }
  ]),
  ask_equipment: IK([
    { row: { buttons: [btn('Casa sin equipo','bodyweight')] } },
    { row: { buttons: [btn('Casa con mancuernas/bandas','home_basic')] } },
    { row: { buttons: [btn('Gimnasio','full_gym')] } }
  ]),
  ask_training_days: IK([
    { row: { buttons: [btn('2','2'),btn('3','3'),btn('4','4'),btn('5','5'),btn('6','6')] } }
  ]),
  ask_injuries: IK([
    { row: { buttons: [btn('No, estoy bien','no'), btn('Si, tengo','yes')] } }
  ]),
  ask_wake_time: IK([
    { row: { buttons: [
      btn('5:00','05:00'),btn('6:00','06:00'),btn('7:00','07:00'),
      btn('8:00','08:00'),btn('9:00','09:00'),btn('Otra','custom')
    ] } }
  ]),
  ask_activity_level: IK([
    { row: { buttons: [btn('Sentado casi todo el dia','sedentary')] } },
    { row: { buttons: [btn('Camino algo, tareas ligeras','lightly_active')] } },
    { row: { buttons: [btn('De pie bastante, camino mucho','moderately_active')] } },
    { row: { buttons: [btn('Trabajo fisico pesado','very_active')] } }
  ]),
  confirm_profile: IK([
    { row: { buttons: [btn('Todo bien, dale','confirm'), btn('Quiero corregir algo','correct')] } }
  ]),
  correct_block: IK([
    { row: { buttons: [btn('Datos fisicos','block_1'), btn('Objetivo','block_2')] } },
    { row: { buttons: [btn('Alimentacion','block_3'), btn('Ejercicio','block_4')] } },
    { row: { buttons: [btn('Horarios','block_5')] } }
  ]),
  ask_phone: {
    type: 'replyKeyboard',
    replyKeyboard: {
      rows: [{ row: { buttons: [{ text: 'Compartir mi numero', requestContact: true }] } }]
    },
    replyKeyboardOptions: { resizeKeyboard: true, oneTimeKeyboard: true }
  }
};

const kb = KEYBOARDS[state.step] || null;

// ─── AI message payload ────────────────────────────────────────────────────────
const userMessage = JSON.stringify({
  step:             state.step,
  user_response:    userResponse,
  validation_error: isValidationError,
  user_name:        stateData.first_name || null,
  collected_data: {
    gender:    stateData.gender    || null,
    age:       stateData.age       || null,
    weight_kg: stateData.weight_kg || null,
    goal_type: stateData.goal_type || null
  }
});

return [{
  json: {
    userMessage,
    chatId:              .first().json.chatId,
    replyMarkupType:     kb ? kb.type : 'none',
    inlineKeyboard:      (kb && kb.type === 'inlineKeyboard')  ? kb.inlineKeyboard  : null,
    replyKeyboard:       (kb && kb.type === 'replyKeyboard')   ? kb.replyKeyboard   : null,
    replyKeyboardOptions:(kb && kb.replyKeyboardOptions)        ? kb.replyKeyboardOptions : null
  }
}];
